#include <stdio.h>
int main() {
    int T, N, Li, Ui, i, j;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        int scores[N];
        int ranges[N][2];
        for (i = 0; i < N; i++) {
            scanf("%d %d", &Li, &Ui);
            ranges[i][0] = Li;
            ranges[i][1] = Ui;
            scores[i] = 0;
        }
        for (i = 0; i < N; i++) {
            for (j = 0; j < N; j++) {
                if (i != j) {
                    if (ranges[i][0] <= ranges[j][0] && ranges[j][1] <= ranges[i][1]) {
                        scores[i] += 2;
                    } else if (ranges[j][0] <= ranges[i][0] && ranges[i][1] <= ranges[j][1]) {
                        scores[j] += 2;
                    } else {
                        scores[i] += 1;
                        scores[j] += 1;
                    }
                }
            }
        }
        for (i = 0; i < N; i++) {
            printf("%d ", scores[i]);
        }
        printf("\n");
    }
    return 0;
}

