    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] scores = new int[N];
            int[][] ranges = new int[N][2];
            for (int i = 0; i < N; i++) {
                int Li = sc.nextInt();
                int Ui = sc.nextInt();
                ranges[i][0] = Li;
                ranges[i][1] = Ui;
            }
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < N; j++) {
                    if (i != j) {
                        if (ranges[i][0] <= ranges[j][0] && ranges[j][1] <= ranges[i][1]) {
                            scores[i] += 2;
                        } else if (ranges[j][0] <= ranges[i][0] && ranges[i][1] <= ranges[j][1]) {
