    const N = parseInt(readline());
    const scores = new Array(N).fill(0);
    const ranges = [];
    for (let i = 0; i < N; i++) {
        const [Li, Ui] = readline().split(' ').map(Number);
        ranges.push([Li, Ui]);
    }
    for (let i = 0; i < N; i++) {
        for (let j = 0; j < N; j++) {
            if (i !== j) {
                if (ranges[i][0] <= ranges[j][0] && ranges[j][1] <= ranges[i][1]) {
                    scores[i] += 2;
